import scala.collection.mutable.Deque
import scala.collection.mutable.HashMap

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L

  val maxNum = 1000000
  val spf = Array.fill(maxNum + 1)(0)
  for (i <- 2 to maxNum) spf(i) = i

  for (i <- 2 to math.sqrt(maxNum).toInt + 1) {
    if (spf(i) == i) {
      for (j <- i * i to maxNum by i) {
        if (spf(j) == j) spf(j) = i
      }
    }
  }

  val primeLists = HashMap[Int, List[Int]]()
  for (idx <- 0 until n) {
    val x = nums(idx).toInt
    if (x == 1) continue
    var temp = x
    val factors = scala.collection.mutable.Set[Int]()
    while (temp > 1) {
      val p = spf(temp)
      factors += p
      while (temp % p == 0) temp /= p
    }
    for (p <- factors) {
      primeLists(p) = primeLists.getOrElse(p, List()).toList :+ idx
    }
  }

  val visited = Array.fill(n)(false)
  val queue = Deque[(Int, Int)]()
  queue += (0, 0)
  visited(0) = true

  while (queue.nonEmpty) {
    val (pos, steps) = queue.head
    queue.removeHead()
    if (pos == n - 1) return steps.toLong
    for (nextPos <- List(pos - 1, pos + 1)) {
      if (nextPos >= 0 && nextPos < n && !visited(nextPos)) {
        visited(nextPos) = true
        queue += (nextPos, steps + 1)
      }
    }
    val x = nums(pos).toInt
    if (x > 1 && spf(x) == x) {
      val indices = primeLists.get(x)
      indices.foreach { lst =>
        for (j <- lst) {
          if (j != pos && !visited(j)) {
            visited(j) = true
            queue += (j, steps + 1)
          }
        }
      }
    }
  }
  -1L
}
